def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # 缓存超体积计算
    hv_cache = {}

    def compute_hv(indices):
        """计算索引子集的超体积，使用缓存"""
        if not indices:
            return 0.0
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        data = points[list(indices)]
        hv = pg.hypervolume(data)
        result = hv.compute(reference_point)
        hv_cache[key] = result
        return result

    def greedy_init():
        """贪心初始化"""
        selected = set()
        for _ in range(k):
            best_contrib = -np.inf
            best_idx = -1
            for idx in range(n):
                if idx in selected:
                    continue
                contrib = compute_hv(selected | {idx}) - compute_hv(selected)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx
            selected.add(best_idx)
        return selected

    def incremental_swap(current_set, pool_size=30):
        """增量交换搜索"""
        current_hv = compute_hv(current_set)
        improved = True
        while improved:
            improved = False
            # 计算贡献
            contribs = {}
            for idx in current_set:
                contribs[idx] = current_hv - compute_hv(current_set - {idx})
            # 排序贡献最低的点
            low_contrib = sorted(contribs.items(), key=lambda x: x[1])[:max(3, k//2)]
            # 构建候选池
            unselected = [i for i in range(n) if i not in current_set]
            if len(unselected) > pool_size:
                # 基于到当前子集的最小距离选择候选
                selected_pts = points[list(current_set)]
                unselected_pts = points[unselected]
                dists = np.min(np.linalg.norm(unselected_pts[:, None] - selected_pts, axis=2), axis=1)
                pool = [unselected[i] for i in np.argsort(dists)[:pool_size]]
            else:
                pool = unselected
            # 尝试替换
            for remove_idx, _ in low_contrib:
                for cand in pool:
                    if cand in current_set:
                        continue
                    # 增量计算
                    old_contrib = contribs[remove_idx]
                    new_contrib = compute_hv((current_set - {remove_idx}) | {cand}) - compute_hv(current_set - {remove_idx})
                    new_hv = current_hv - old_contrib + new_contrib
                    if new_hv > current_hv + 1e-12:
                        current_set.remove(remove_idx)
                        current_set.add(cand)
                        current_hv = new_hv
                        improved = True
                        break
                if improved:
                    break
        return current_set, current_hv

    # 多起点搜索
    num_starts = max(3, min(10, n // 50))
    best_set = None
    best_hv = -np.inf

    for start in range(num_starts):
        if start == 0:
            current_set = greedy_init()
        elif start == 1:
            current_set = set(random.sample(range(n), k))
        else:
            if best_set is not None:
                current_set = best_set.copy()
                # 扰动
                replace = random.sample(list(current_set), max(1, k//4))
                unsel = [i for i in range(n) if i not in current_set]
                for r in replace:
                    if unsel:
                        current_set.remove(r)
                        current_set.add(random.choice(unsel))
            else:
                current_set = set(random.sample(range(n), k))

        current_set, current_hv = incremental_swap(current_set)
        if current_hv > best_hv:
            best_hv = current_hv
            best_set = current_set.copy()

    # 最终精炼：穷举单点替换
    if best_set is not None:
        improved = True
        while improved:
            improved = False
            contribs = {idx: best_hv - compute_hv(best_set - {idx}) for idx in best_set}
            sorted_low = sorted(contribs.items(), key=lambda x: x[1])[:max(2, k//3)]
            for remove_idx, _ in sorted_low:
                for cand in range(n):
                    if cand in best_set:
                        continue
                    new_set = (best_set - {remove_idx}) | {cand}
                    new_hv = compute_hv(new_set)
                    if new_hv > best_hv + 1e-12:
                        best_set = new_set
                        best_hv = new_hv
                        improved = True
                        break
                if improved:
                    break

    return points[list(best_set)] if best_set is not None else np.array([])

def HSS(points, k: int, reference_point) -> np.ndarray:
    import pygmo as pg

    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # 超体积计算缓存
    hv_cache: Dict[frozenset, float] = {}

    def compute_hypervolume(indices: Set[int]) -> float:
        """计算索引集合的超体积"""
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        data = points[list(indices)]
        hv = pg.hypervolume(data)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    def hypervolume_gain(current_set: Set[int], candidate: int) -> float:
        """计算添加候选点带来的超体积增量"""
        if candidate in current_set:
            return 0.0
        new_set = current_set | {candidate}
        return compute_hypervolume(new_set) - compute_hypervolume(current_set)

    def greedy_initialization() -> Set[int]:
        """贪心初始化：每次选择贡献最大的点"""
        current_set = set()
        remaining = set(range(n))

        while len(current_set) < k:
            best_gain = -np.inf
            best_idx = None
            for idx in remaining:
                gain = hypervolume_gain(current_set, idx)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                current_set.add(best_idx)
                remaining.remove(best_idx)
        return current_set

    def compute_marginal_contributions(current_set: Set[int]) -> Dict[int, float]:
        """计算当前集合中每个点的边际贡献"""
        contributions = {}
        current_hv = compute_hypervolume(current_set)
        for idx in current_set:
            temp_set = current_set - {idx}
            contributions[idx] = current_hv - compute_hypervolume(temp_set)
        return contributions

    def targeted_local_search(current_set: Set[int], candidate_pool: Set[int], 
                              max_swaps: int = 5) -> Tuple[Set[int], float, bool]:
        """针对低贡献点的局部搜索"""
        current_hv = compute_hypervolume(current_set)
        contributions = compute_marginal_contributions(current_set)

        # 按贡献排序，选择最低贡献的点
        sorted_contrib = sorted(contributions.items(), key=lambda x: x[1])
        low_contrib_points = [idx for idx, _ in sorted_contrib[:min(3, len(sorted_contrib))]]

        improved = False
        for remove_idx in low_contrib_points:
            if max_swaps <= 0:
                break

            best_gain = 0.0
            best_add = None

            # 从候选池中寻找最佳替换
            for candidate in candidate_pool:
                if candidate in current_set:
                    continue

                # 计算交换后的超体积
                new_set = (current_set - {remove_idx}) | {candidate}
                new_hv = compute_hypervolume(new_set)
                gain = new_hv - current_hv

                if gain > best_gain:
                    best_gain = gain
                    best_add = candidate

            if best_add is not None:
                current_set = (current_set - {remove_idx}) | {best_add}
                current_hv += best_gain
                candidate_pool.remove(best_add)
                candidate_pool.add(remove_idx)
                improved = True
                max_swaps -= 1

        return current_set, current_hv, improved

    def exhaustive_one_point_refinement(current_set: Set[int]) -> Tuple[Set[int], float]:
        """最终精炼：尝试替换每个选中点"""
        current_hv = compute_hypervolume(current_set)
        unselected = set(range(n)) - current_set

        for remove_idx in list(current_set):
            best_gain = 0.0
            best_add = None

            for candidate in unselected:
                new_set = (current_set - {remove_idx}) | {candidate}
                new_hv = compute_hypervolume(new_set)
                gain = new_hv - current_hv

                if gain > best_gain:
                    best_gain = gain
                    best_add = candidate

            if best_add is not None:
                current_set = (current_set - {remove_idx}) | {best_add}
                current_hv += best_gain
                unselected.remove(best_add)
                unselected.add(remove_idx)

        return current_set, current_hv

    # 多起点搜索
    num_starts = max(3, n // 15)
    best_set = None
    best_hv = -np.inf

    for start in range(num_starts):
        # 初始化当前解
        if start == 0:
            current_set = greedy_initialization()
        else:
            current_set = set(random.sample(range(n), k))

        current_hv = compute_hypervolume(current_set)

        # 构建自适应候选池
        candidate_pool = set()
        all_indices = set(range(n))
        unselected = all_indices - current_set

        # 添加随机未选点
        pool_size = min(2 * k, len(unselected))
        if unselected:
            random_candidates = random.sample(list(unselected), min(pool_size, len(unselected)))
            candidate_pool.update(random_candidates)

        # 局部搜索迭代
        max_iterations = 10
        for _ in range(max_iterations):
            current_set, current_hv, improved = targeted_local_search(current_set, candidate_pool)
            if not improved:
                break

            # 更新候选池，保持多样性
            if len(candidate_pool) < 2 * k:
                remaining = all_indices - current_set - candidate_pool
                if remaining:
                    new_candidate = random.choice(list(remaining))
                    candidate_pool.add(new_candidate)

        # 最终精炼
        current_set, current_hv = exhaustive_one_point_refinement(current_set)

        # 更新最佳解
        if current_hv > best_hv:
            best_hv = current_hv
            best_set = current_set.copy()

    # 返回结果
    selected_indices = list(best_set)
    return points[selected_indices]

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # 超体积缓存
    hv_cache = {}

    def compute_hv(indices: Set[int]) -> float:
        """计算索引集合的超体积"""
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        data = points[list(indices)]
        hv = pg.hypervolume(data)
        result = hv.compute(reference_point)
        hv_cache[key] = result
        return result

    def incremental_contrib(current_set: Set[int], candidate: int) -> float:
        """增量计算候选点对当前集合的超体积贡献"""
        if candidate in current_set:
            return 0.0
        new_set = frozenset(current_set | {candidate})
        return compute_hv(new_set) - compute_hv(current_set)

    # 多起点搜索
    num_starts = max(2, min(5, n // 100))
    best_set = None
    best_hv = -np.inf

    for start in range(num_starts):
        # 初始化当前解
        if start == 0:
            # 贪心初始化
            current_set = set()
            remaining = list(range(n))
            random.shuffle(remaining)
            candidate_pool = set(remaining[:min(2*k, n)])

            for _ in range(k):
                best_cand = None
                best_contrib = -np.inf
                for cand in candidate_pool:
                    if cand not in current_set:
                        contrib = incremental_contrib(current_set, cand)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_cand = cand
                if best_cand is not None:
                    current_set.add(best_cand)
                    candidate_pool.remove(best_cand)
                else:
                    # 从剩余点中随机选择
                    remaining_set = set(range(n)) - current_set
                    if remaining_set:
                        current_set.add(random.choice(list(remaining_set)))
        else:
            # 随机初始化或扰动最优解
            if best_set is not None and start == 1:
                current_set = best_set.copy()
                # 扰动：随机替换部分点
                num_replace = max(1, k // 5)
                replace_idx = random.sample(list(current_set), num_replace)
                for idx in replace_idx:
                    current_set.remove(idx)
                    remaining_set = set(range(n)) - current_set
                    if remaining_set:
                        current_set.add(random.choice(list(remaining_set)))
            else:
                current_set = set(random.sample(range(n), k))
            candidate_pool = set(random.sample(range(n), min(2*k, n)))

        # 局部搜索：交换低贡献点
        max_iter = 50
        for _ in range(max_iter):
            improved = False
            current_hv = compute_hv(current_set)

            # 计算当前集合中每个点的贡献
            contributions = {}
            for idx in current_set:
                temp_set = current_set - {idx}
                contributions[idx] = current_hv - compute_hv(temp_set)

            # 选择贡献最低的点
            low_contrib = sorted(contributions.keys(), key=lambda x: contributions[x])[:min(3, k)]

            # 尝试替换低贡献点
            for low_idx in low_contrib:
                for cand in candidate_pool:
                    if cand in current_set:
                        continue
                    # 增量评估
                    new_set = (current_set - {low_idx}) | {cand}
                    new_hv = compute_hv(new_set)
                    if new_hv > current_hv + 1e-12:
                        current_set = new_set
                        improved = True
                        break
                if improved:
                    break

            if not improved:
                break

        # 最终确定性单点替换扫描
        current_hv = compute_hv(current_set)
        for idx in list(current_set):
            best_gain = -np.inf
            best_cand = None
            for cand in candidate_pool:
                if cand in current_set:
                    continue
                new_set = (current_set - {idx}) | {cand}
                new_hv = compute_hv(new_set)
                gain = new_hv - current_hv
                if gain > best_gain:
                    best_gain = gain
                    best_cand = cand
            if best_gain > 0:
                current_set = (current_set - {idx}) | {best_cand}
                current_hv += best_gain

        # 更新最优解
        final_hv = compute_hv(current_set)
        if final_hv > best_hv:
            best_hv = final_hv
            best_set = current_set.copy()

    # 确保返回恰好k个点
    if best_set is None:
        indices = random.sample(range(n), k)
        return points[indices]

    selected_indices = list(best_set)
    if len(selected_indices) > k:
        # 保留贡献最大的k个点
        contributions = []
        for idx in selected_indices:
            temp_set = best_set - {idx}
            contributions.append(best_hv - compute_hv(temp_set))
        top_k_idx = np.argsort(contributions)[-k:]
        selected_indices = [selected_indices[i] for i in top_k_idx]
    elif len(selected_indices) < k:
        # 补充随机点
        remaining = set(range(n)) - best_set
        need = k - len(selected_indices)
        extra = random.sample(list(remaining), min(need, len(remaining)))
        selected_indices.extend(extra)

    return points[selected_indices]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # 初始化候选池（大小为 2k）
    candidate_pool_size = min(2 * k, n)
    indices = list(range(n))
    random.shuffle(indices)
    candidate_pool = set(indices[:candidate_pool_size])

    # 缓存超体积贡献
    contribution_cache = {}

    def compute_hv_contribution(subset_indices, element_idx):
        """计算元素对子集的超体积贡献（带缓存）"""
        cache_key = (frozenset(subset_indices), element_idx)
        if cache_key in contribution_cache:
            return contribution_cache[cache_key]

        if not subset_indices:
            subset_points = np.empty((0, m))
        else:
            subset_points = points[list(subset_indices)]

        # 计算包含元素的超体积
        if not (subset_indices | {element_idx}):
            combined_points = np.empty((0, m))
        else:
            combined_points = points[list(subset_indices | {element_idx})]

        if subset_points.size == 0:
            hv_subset = 0.0
        else:
            try:
                hv = pg.hypervolume(subset_points)
                hv_subset = hv.compute(reference_point)
            except:
                hv_subset = 0.0

        if combined_points.size == 0:
            hv_combined = 0.0
        else:
            try:
                hv = pg.hypervolume(combined_points)
                hv_combined = hv.compute(reference_point)
            except:
                hv_combined = 0.0

        contribution = hv_combined - hv_subset
        contribution_cache[cache_key] = contribution
        return contribution

    # 初始贪心选择
    current_subset = set()
    remaining_candidates = candidate_pool.copy()

    for _ in range(k):
        if not remaining_candidates:
            break

        best_candidate = None
        best_contribution = -float('inf')

        for candidate in remaining_candidates:
            contribution = compute_hv_contribution(current_subset, candidate)
            if contribution > best_contribution:
                best_contribution = contribution
                best_candidate = candidate

        if best_candidate is not None:
            current_subset.add(best_candidate)
            remaining_candidates.remove(best_candidate)

    # 迭代精炼
    max_iterations = 100
    for iteration in range(max_iterations):
        improved = False

        # 计算当前超体积
        if not current_subset:
            current_points = np.empty((0, m))
        else:
            current_points = points[list(current_subset)]

        if current_points.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_points)
                current_hv = hv.compute(reference_point)
            except:
                current_hv = 0.0

        # 尝试替换操作
        for s in list(current_subset):
            for r in candidate_pool - current_subset:
                # 创建新子集
                new_subset = (current_subset - {s}) | {r}

                # 计算新超体积
                if not new_subset:
                    new_points = np.empty((0, m))
                else:
                    new_points = points[list(new_subset)]

                if new_points.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_points)
                        new_hv = hv.compute(reference_point)
                    except:
                        new_hv = 0.0

                # 如果改进则接受
                if new_hv > current_hv:
                    current_subset = new_subset
                    improved = True
                    break

            if improved:
                break

        # 如果没有改进，尝试多样性增强的突变
        if not improved and iteration % 5 == 0:
            # 计算点之间的最小距离
            if len(current_subset) > 1:
                subset_points = points[list(current_subset)]
                distances = cdist(subset_points, subset_points)
                np.fill_diagonal(distances, np.inf)
                min_dist = np.min(distances)

                # 寻找可以增加多样性的替换
                for s in list(current_subset):
                    for r in candidate_pool - current_subset:
                        # 检查是否增加多样性
                        temp_subset = (current_subset - {s}) | {r}
                        temp_points = points[list(temp_subset)]

                        if len(temp_subset) > 1:
                            temp_distances = cdist(temp_points, temp_points)
                            np.fill_diagonal(temp_distances, np.inf)
                            temp_min_dist = np.min(temp_distances)

                            if temp_min_dist > min_dist * 1.1:  # 多样性增加10%以上
                                current_subset = temp_subset
                                improved = True
                                break

                    if improved:
                        break

        # 如果没有改进，退出循环
        if not improved:
